  	import com.google.gson.Gson;  
    import com.google.gson.GsonBuilder; 
    import org.json.JSONArray;
  	import org.json.JSONException;
  	import org.json.JSONObject;
    import sailpoint.object.*;
    import sailpoint.tools.*;
    import sailpoint.connector.webservices.WebServicesClient;
 		import java.text.ParseException;
		import java.text.SimpleDateFormat;
		import java.util.Date;
  	import org.apache.commons.logging.Log;
  	import org.apache.commons.logging.LogFactory;
  
    Log logger = LogFactory.getLog("MDStaff-Ascension Common RuleLibrary");
	  
  
  	public String getLatestAccessToken(WebServicesClient client)
  	{
      logger.debug("Entering method getLatestAccessToken"); 
			Application appObj = context.getObjectByName(Application.class,"MDStaff - Ascension");
      String tokenUrl = null;
      String clientId = null;
      String clientSecret = null;
      String webServiceBaseURL =null;
      if(null!=appObj)
      {
        webServiceBaseURL = appObj.getAttributeValue("genericWebServiceBaseUrl");
        tokenUrl = webServiceBaseURL+"/api/tokens";
        clientId = context.decrypt(appObj.getAttributeValue("clientId_CA"));
        clientSecret = context.decrypt(appObj.getAttributeValue("clientSecret_CA"));
      }
  
  		String currentAccessToken = null;
      List allowedStatuses = new ArrayList();
      allowedStatuses.add("200");

      Map payLoadMap = new HashMap();

      payLoadMap.put("grant_type", "password");
      payLoadMap.put("username", clientId);
      payLoadMap.put("password", clientSecret);
      payLoadMap.put("instance", "asc");
      payLoadMap.put("facilityId", "4a8331e6-01fa-4861-9c5c-dee3f78663bb");


      Map headersMap = new HashMap();

      headersMap.put("Content-Type", "application/x-www-form-urlencoded");

 			String jsonResponse = null;
      try
      {
         jsonResponse  = client.executePost(tokenUrl,payLoadMap,headersMap,allowedStatuses,false);

         if (Util.isNotNullOrEmpty(jsonResponse)) 
         {	  
             Gson gson = new GsonBuilder().create();  

             Map tokenMap = gson.fromJson(jsonResponse, HashMap.class);  

             if (null != tokenMap && !tokenMap.isEmpty()) 
             {  
                String token = tokenMap.get("access_token");  

                if(Util.isNotNullOrEmpty(token))
                {
                  currentAccessToken = token;
                }
             }
        	}
      } 
      catch(Exception e) 
      {
        currentAccessToken = null;
      }
  		logger.debug("Exiting method getLatestAccessToken");
   	  return currentAccessToken;
  	}
  
    public String formatDate(String datestr)
    {
      //logger.debug("Entering method formatDate");
      String formattedDate = "";
      try
      {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
        SimpleDateFormat output = new SimpleDateFormat("MM/dd");
        Date d = sdf.parse(datestr);
        formattedDate = output.format(d);
      }
      catch(Exception e)
      {
        logger.error("Error occurred parsing DOB. Details:\n"+e.getMessage());
      }
      //logger.debug("Entering method formatDate");
      return formattedDate;
    }
